// O(n²) time, O(1) space
function insertionSort(arr) {
  const result = [];
  for (let i = 1; i < arr.length; i++) {
    let j = i;
    while (j > 0 && arr[j-1] > arr[j]) {
      [arr[j], arr[j-1]] = [arr[j-1], arr[j]];
      j--;
    }
    result.push([...arr]);
  }
  return result;
}
